let g_module: Uint8Array | undefined;
let g_wasmBinary: Uint8Array | undefined;
export default function() {
    if (!g_wasmBinary) {
        g_wasmBinary = decompress(decode(blobStr));
    }
    if (!g_module) {
        g_module = wrapper({
            wasmBinary: g_wasmBinary,
            locateFile: undefined
        });
    }
    return g_module;

}

export function reset() {
    if (g_module) {
        g_module = undefined;
    }
}
